import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import '../styles/Profile.css';

const Profile = () => {
  const [userData, setUserData] = useState(null);
  const [userEmail, setUserEmail] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState(null);
  const [success, setSuccess] = useState(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const navigate = useNavigate();

  useEffect(() => {
    const userId = localStorage.getItem('user_id');
    if (!userId) {
      navigate('/');
      return;
    }

    const fetchUserData = async () => {
      setIsLoading(true);
      try {
        // Fetch user data
        const response = await fetch(`http://localhost:5000/api/users/${userId}`);
        if (!response.ok) {
          throw new Error('Failed to fetch user data');
        }
        const data = await response.json();
        setUserData(data);

        // Fetch user email in a separate request
        const emailResponse = await fetch(`http://localhost:5000/api/users/email/${userId}`);
        if (emailResponse.ok) {
          const emailData = await emailResponse.json();
          setUserEmail(emailData.email || '');
        }
      } catch (err) {
        setError(err.message);
      } finally {
        setIsLoading(false);
      }
    };

    fetchUserData();
  }, [navigate]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setUserData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError(null);
    setSuccess(null);

    try {
      const userId = localStorage.getItem('user_id');
      const response = await fetch(`http://localhost:5000/api/users/${userId}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(userData)
      });

      if (!response.ok) {
        throw new Error('Failed to update profile');
      }

      setSuccess('Profile updated successfully!');
      setTimeout(() => setSuccess(null), 3000);
    } catch (err) {
      setError(err.message);
    }
  };

  const hasChanges = () => {
    if (!userData) return false;

    const userId = localStorage.getItem('user_id');

    // Compare current userData with original data
    return userId === userData.user_id &&
      (originalUserData && (
        originalUserData.name !== userData.name ||
        originalUserData.age !== userData.age ||
        originalUserData.sex !== userData.sex ||
        originalUserData.is_smoker !== userData.is_smoker ||
        originalUserData.has_allergies !== userData.has_allergies
      ));
  };

  const [originalUserData, setOriginalUserData] = useState(null);

  useEffect(() => {
    if (userData && !originalUserData) {
      setOriginalUserData(userData);
    }
  }, [userData, originalUserData]);

  const navigateTo = (path) => {
    setIsSidebarOpen(false);
    navigate(path);
  };

  if (isLoading) {
    return <div className="profile-container">
      <div className="profile-loading">Loading user data...</div>
    </div>;
  }

  return (
    <div className="profile-container">
      <div className={`sidebar ${isSidebarOpen ? 'open' : ''}`}>
        <div className="sidebar-header">
          <h2>Menu</h2>
        </div>
        <nav className="sidebar-nav">
          <button onClick={() => navigateTo('/')}>Home</button>
          <button onClick={() => navigateTo('/recording-indicators')}>Recording Indicators</button>
          <button onClick={() => navigateTo('/exacerbation-forecast')}>Exacerbation Forecast</button>
          <button onClick={() => navigateTo('/graphs-of-changes')}>Graphs of Changes</button>
          <button onClick={() => navigateTo('/medication-diary')}>Medication Diary</button>
          <button 
            className="active" 
            onClick={() => navigateTo('/profile')}
          >
            Profile
          </button>
        </nav>
      </div>

      <div 
        className="floating-menu-button"
        onClick={() => setIsSidebarOpen(!isSidebarOpen)}
      >
        <span></span>
        <span></span>
        <span></span>
      </div>

      <div className="profile-content">
        <h1 className="profile-heading">User Profile</h1>

        {error && <div className="profile-error-message">{error}</div>}
        {success && <div className="profile-success-message">{success}</div>}

        {userData && (
          <form className="profile-form" onSubmit={handleSubmit}>
            <div className="profile-form-group">
              <input
                type="email"
                className="profile-input"
                value={userEmail}
                disabled
                placeholder=" "
              />
              <label className="profile-label">Email</label>
            </div>

            <div className="profile-form-group">
              <input
                type="text"
                name="name"
                className="profile-input"
                value={userData.name || ''}
                onChange={handleChange}
                placeholder=" "
              />
              <label className="profile-label">Name</label>
            </div>

            <div className="profile-form-group">
              <input
                type="number"
                name="age"
                className="profile-input"
                value={userData.age || ''}
                onChange={handleChange}
                placeholder=" "
                min="1"
                max="120"
              />
              <label className="profile-label">Age</label>
            </div>

            <div className="profile-select-group">
              <label className="profile-select-label">Sex</label>
              <select
                name="sex"
                className="profile-select"
                value={userData.sex || ''}
                onChange={handleChange}
              >
                <option value="">Select</option>
                <option value="male">Male</option>
                <option value="female">Female</option>
                <option value="other">Other</option>
              </select>
            </div>

            <div>
              <p className="profile-radio-label">Smoking Status</p>
              <div className="profile-radio-group">
                <label className="profile-radio-option">
                  <input
                    type="radio"
                    name="is_smoker"
                    className="profile-radio"
                    value="true"
                    checked={userData.is_smoker === true}
                    onChange={() => setUserData({ ...userData, is_smoker: true })}
                  />
                  <span className="profile-radio-text">Yes</span>
                </label>
                <label className="profile-radio-option">
                  <input
                    type="radio"
                    name="is_smoker"
                    className="profile-radio"
                    value="false"
                    checked={userData.is_smoker === false}
                    onChange={() => setUserData({ ...userData, is_smoker: false })}
                  />
                  <span className="profile-radio-text">No</span>
                </label>
              </div>
            </div>

            <div>
              <p className="profile-radio-label">Allergies</p>
              <div className="profile-radio-group">
                <label className="profile-radio-option">
                  <input
                    type="radio"
                    name="has_allergies"
                    className="profile-radio"
                    value="true"
                    checked={userData.has_allergies === true}
                    onChange={() => setUserData({ ...userData, has_allergies: true })}
                  />
                  <span className="profile-radio-text">Yes</span>
                </label>
                <label className="profile-radio-option">
                  <input
                    type="radio"
                    name="has_allergies"
                    className="profile-radio"
                    value="false"
                    checked={userData.has_allergies === false}
                    onChange={() => setUserData({ ...userData, has_allergies: false })}
                  />
                  <span className="profile-radio-text">No</span>
                </label>
              </div>
            </div>

            <button 
              type="submit" 
              className="profile-save-button"
              disabled={!hasChanges()}
            >
              Save Changes
            </button>
          </form>
        )}
      </div>
    </div>
  );
};

export default Profile;
